class Solution:
    def numberOfGoodPaths(self, vals, edges):
        from collections import defaultdict
        n = len(vals)
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        count = 0
        for start in range(n):
            # BFS to every node, tracking the max value on the path
            stack = [(start, vals[start], -1)]
            while stack:
                node, mx, parent = stack.pop()
                if node != start and vals[node] == vals[start] and mx == vals[start] and node > start:
                    count += 1
                for nb in adj[node]:
                    if nb != parent:
                        stack.append((nb, max(mx, vals[nb]), node))
        return count + n

