class Solution:
    def numberOfGoodPaths(self, vals, edges):
        from collections import defaultdict
        n = len(vals)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        by_value = defaultdict(list)
        for i, v in enumerate(vals):
            by_value[v].append(i)
        adj = defaultdict(list)
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        active = [False] * n
        result = n
        for v in sorted(by_value):
            nodes = by_value[v]
            for u in nodes:
                active[u] = True
                for w in adj[u]:
                    if active[w]:
                        ru, rw = find(u), find(w)
                        if ru != rw:
                            parent[ru] = rw
            counts = defaultdict(int)
            for u in nodes:
                counts[find(u)] += 1
            for c in counts.values():
                result += c * (c - 1) // 2
        return result

