var numberOfGoodPaths = function(vals, edges) {
    const n = vals.length;
    const parent = Array.from({length: n}, (_, i) => i);
    const find = (x) => {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    };
    const byValue = new Map();
    for (let i = 0; i < n; i++) {
        if (!byValue.has(vals[i])) byValue.set(vals[i], []);
        byValue.get(vals[i]).push(i);
    }
    const adj = Array.from({length: n}, () => []);
    for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
    const active = new Array(n).fill(false);
    let result = n;
    const sortedVals = [...byValue.keys()].sort((a, b) => a - b);
    for (const v of sortedVals) {
        const nodes = byValue.get(v);
        for (const u of nodes) {
            active[u] = true;
            for (const w of adj[u]) {
                if (active[w]) {
                    const ru = find(u), rw = find(w);
                    if (ru !== rw) parent[ru] = rw;
                }
            }
        }
        const counts = new Map();
        for (const u of nodes) {
            const r = find(u);
            counts.set(r, (counts.get(r) || 0) + 1);
        }
        for (const c of counts.values()) result += c * (c - 1) / 2;
    }
    return result;
};
